import { isNull, loadProperty, } from "@tsparticles/engine";
import { BubbleBase } from "./BubbleBase.js";
export class BubbleDiv extends BubbleBase {
    selectors = [];
    load(data) {
        super.load(data);
        if (isNull(data)) {
            return;
        }
        loadProperty(this, "selectors", data.selectors);
    }
}
