import { Preload } from "./Options/Classes/Preload.js";
export class ImagePreloaderPlugin {
    id = "image-preloader";
    #engine;
    constructor(engine) {
        this.#engine = engine;
    }
    async getPlugin(container) {
        const { ImagePreloaderInstance } = await import("./ImagePreloaderInstance.js");
        return new ImagePreloaderInstance(this.#engine, container);
    }
    loadOptions(_container, options, source) {
        if (!source?.preload) {
            return;
        }
        options.preload ??= [];
        const preloadOptions = options.preload;
        for (const item of source.preload) {
            const existing = preloadOptions.find(t => t.name === item.name || t.src === item.src);
            if (existing) {
                existing.load(item);
            }
            else {
                const preload = new Preload();
                preload.load(item);
                preloadOptions.push(preload);
            }
        }
    }
    needsPlugin() {
        return true;
    }
}
