import { isNull, loadProperty } from "@tsparticles/engine";
import { GrabLinks } from "./GrabLinks.js";
export class Grab {
    distance = 100;
    links = new GrabLinks();
    load(data) {
        if (isNull(data)) {
            return;
        }
        loadProperty(this, "distance", data.distance);
        this.links.load(data.links);
    }
}
